import { TestingModule } from '@nestjs/testing';
import { DataSource, Repository } from 'typeorm';
import { createIntegrationTestModule, cleanDatabase } from './setup';
import { ShipmentItem } from '../../src/entities/shipment-item.entity';
import { buildShipmentItem } from '../factories/shipment-item.factory';
import { Shipment } from '../../src/entities/shipment.entity';
import { buildShipment } from '../factories/shipment.factory';

describe('ShipmentItem Relationships', () => {
  let module: TestingModule;
  let dataSource: DataSource;
  let repository: Repository<ShipmentItem>;
  let shipmentId: string;

  beforeAll(async () => {
    module = await createIntegrationTestModule();
    dataSource = module.get(DataSource);
    repository = dataSource.getRepository(ShipmentItem);
  });

  beforeEach(async () => {
    const shipmentEntity = await dataSource
      .getRepository(Shipment)
      .save(
        dataSource.getRepository(Shipment).create(
          buildShipment(),
        ),
      );
    shipmentId = shipmentEntity.id;
  });

  afterEach(async () => {
    await cleanDatabase(dataSource);
  });

  afterAll(async () => {
    await module.close();
  });

  describe('belongs_to Shipment', () => {
    it('persists shipmentId reference', async () => {
      const data = buildShipmentItem({ shipmentId: shipmentId });
      const saved = await repository.save(repository.create(data));
      expect(saved.shipmentId).toBe(shipmentId);
    });

    it('loads parent via relation', async () => {
      const data = buildShipmentItem({ shipmentId: shipmentId });
      const saved = await repository.save(repository.create(data));
      const loaded = await repository.findOne({
        where: { id: saved.id } as Record<string, unknown>,
        relations: ['shipment'],
      });
      expect(loaded).not.toBeNull();
      expect(loaded!.shipment).toBeDefined();
      expect(loaded!.shipment.id).toBe(shipmentId);
    });

    it('rejects entity without required shipmentId', async () => {
      const data = buildShipmentItem({ shipmentId: undefined as unknown as string });
      await expect(
        repository.save(repository.create(data)),
      ).rejects.toThrow();
    });
  });
});
